#nullable enable // autogenerated

using MVZ2.GameContent.Buffs.Enemies;
using MVZ2.GameContent.Buffs.Entities;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using MVZ2Logic.Armors;
using PVZEngine.Armors;
using PVZEngine.Callbacks;
using PVZEngine.Definitions;

namespace MVZ2.GameContent.Armors
{
    [AutoArmorBehaviourDefinition(VanillaArmorBehaviourNames.umbrellaShield)]
    public class UmbrellaShield : ArmorBehaviourDefinition
    {
        public UmbrellaShield(string nsp, string name) : base(nsp, name)
        {
            AddTrigger(LevelCallbacks.POST_ENTITY_DEATH, PostEntityDeathCallback);
        }
        public override void PostUpdate(Armor armor)
        {
            base.PostUpdate(armor);
            var raised = false;
            if (armor.Owner != null && ParatroopBuff.IsParachuting(armor.Owner))
            {
                raised = true;
            }
            armor.SetModelProperty("Raised", raised);
        }
        private void PostEntityDeathCallback(LevelCallbacks.EntityDeathParams param, CallbackResult result)
        {
            var entity = param.entity;
            var info = param.deathInfo;
            if (entity.WillRemoveOnDeath(info))
                return;
            var shield = entity.GetArmorAtSlot(LogicArmorSlots.shield);
            if (shield == null)
                return;
            if (!shield.Definition.HasBehaviour(this))
                return;
            shield.Destroy();
        }
    }
}
